+
+fn strpct_collect(buf: &[c_char]) -> Vec<u8> {
+    let mut out = Vec::new();
+    for &c in buf {
+        let b = c as u8;
+        if b == 0 {
+            break;
+        }
+        out.push(b);
+    }
+    out
+}
+
+#[test]
