+    let mut buf = [0 as c_char; 16];
+    let r = unsafe { strpct(buf.as_mut_ptr(), buf.len(), 33, 100, 0) };
+    assert_eq!(r, buf.as_mut_ptr());
+    assert_eq!(strpct_collect(&buf), b"33".to_vec());
+}
